import React, { useEffect, useState } from 'react';
import { Link, useParams } from 'react-router-dom';
import axios from 'axios';
import { Helmet } from 'react-helmet-async';
import StarRatings from 'react-star-ratings';
import { LazyLoadImage } from 'react-lazy-load-image-component';
import Skeleton from 'react-loading-skeleton';
import 'react-lazy-load-image-component/src/effects/blur.css';
import toast from 'react-hot-toast';
import { useCart } from '../context/CartContext';
import { useWishlist } from '../context/WishlistContext';
import { useAuth } from '../context/AuthContext';
import { productImageUrl } from '../lib/productImage';
import { apiMessage } from '../lib/api';

export default function ProductDetail() {
  const { slug } = useParams();
  const { addToCart } = useCart();
  const { user } = useAuth();
  const { toggleWishlist, products: wishProducts } = useWishlist();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [qty, setQty] = useState(1);
  const [activeImg, setActiveImg] = useState(0);

  useEffect(() => {
    let cancelled = false;
    async function load() {
      setLoading(true);
      try {
        const res = await axios.get(`/api/products/${encodeURIComponent(slug)}`);
        const data = res.data?.data;
        if (!cancelled && data) {
          setProduct(data);
          setActiveImg(0);
        }
      } catch (e) {
        if (!cancelled) {
          setProduct(null);
          toast.error(apiMessage(e, 'Product not found'));
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    }
    load();
    return () => {
      cancelled = true;
    };
  }, [slug]);

  const inWishlist =
    user &&
    product &&
    wishProducts.some((p) => String(p._id || p) === String(product._id));

  const handleAdd = async () => {
    if (!product) return;
    const r = await addToCart(product, qty);
    if (r.success) toast.success(`Added ${qty} × ${product.name}`);
    else toast.error(r.error || 'Could not add to cart');
  };

  const handleWishlist = async () => {
    if (!user) {
      toast.error('Sign in to use your wishlist');
      return;
    }
    if (!product) return;
    const r = await toggleWishlist(product.slug || product._id);
    if (r.success) {
      toast.success(
        r.action === 'added' ? 'Saved to wishlist' : 'Removed from wishlist'
      );
    } else toast.error(r.error);
  };

  if (loading) {
    return (
      <main className="section container product-detail-skeleton">
        <Skeleton height={420} style={{ borderRadius: 12 }} />
        <div style={{ marginTop: 24 }}>
          <Skeleton count={3} />
        </div>
      </main>
    );
  }

  if (!product) {
    return (
      <main className="section container text-center">
        <h1>Product not found</h1>
        <Link to="/products" className="btn btn-primary">
          Back to shop
        </Link>
      </main>
    );
  }

  const images =
    product.images?.length > 0
      ? product.images
      : [{ url: productImageUrl(product) }].filter((x) => x.url);
  const mainUrl = images[activeImg]?.url || productImageUrl(product);

  return (
    <>
      <Helmet>
        <title>{product.name} | Nova Shop</title>
        <meta name="description" content={product.shortDescription || product.description?.slice(0, 160)} />
      </Helmet>
      <header className="page-header">
        <div className="container">
          <ol className="breadcrumb">
            <li>
              <Link to="/">Home</Link>
            </li>
            <li>
              <Link to="/products">Shop</Link>
            </li>
            <li className="active">{product.name}</li>
          </ol>
        </div>
      </header>

      <main className="section product-detail-page">
        <div className="container product-detail-grid">
          <div className="product-detail-gallery">
            <div className="product-detail-main-img">
              <LazyLoadImage
                src={mainUrl}
                alt={product.name}
                effect="blur"
                className="product-detail-main-img__el"
              />
            </div>
            {images.length > 1 && (
              <div className="product-detail-thumbs">
                {images.map((im, i) => (
                  <button
                    key={i}
                    type="button"
                    className={`product-detail-thumb ${i === activeImg ? 'active' : ''}`}
                    onClick={() => setActiveImg(i)}
                  >
                    <img src={im.url} alt="" />
                  </button>
                ))}
              </div>
            )}
          </div>

          <div className="product-detail-info">
            <p className="product-category-label" style={{ textTransform: 'capitalize' }}>
              {typeof product.category === 'string' ? product.category : 'Shop'}
            </p>
            <h1>{product.name}</h1>
            <div className="product-detail-rating-row">
              <StarRatings
                rating={Number(product.rating) || 0}
                starRatedColor="var(--gold)"
                starEmptyColor="#e0ddd6"
                numberOfStars={5}
                name="rating"
                starDimension="22px"
                starSpacing="2px"
              />
              <span className="rating-count">({product.ratingCount || 0} reviews)</span>
            </div>
            <div className="product-detail-price">
              <span className="price-current">£{Number(product.price).toFixed(2)}</span>
              {product.originalPrice != null && (
                <span className="price-original">£{Number(product.originalPrice).toFixed(2)}</span>
              )}
            </div>
            <p className="product-detail-short">{product.shortDescription}</p>
            <div className="product-detail-qty">
              <span className="form-label">Quantity</span>
              <div className="qty-control">
                <button type="button" className="qty-btn" onClick={() => setQty((q) => Math.max(1, q - 1))}>
                  −
                </button>
                <span className="qty-display">{qty}</span>
                <button
                  type="button"
                  className="qty-btn"
                  onClick={() =>
                    setQty((q) =>
                      product.stockQuantity != null ? Math.min(product.stockQuantity, q + 1) : q + 1
                    )
                  }
                >
                  +
                </button>
              </div>
              <span className="stock-hint">
                {product.inStock ? `${product.stockQuantity ?? '—'} in stock` : 'Out of stock'}
              </span>
            </div>
            <div className="product-detail-actions">
              <button
                type="button"
                className="btn btn-primary"
                disabled={!product.inStock}
                onClick={handleAdd}
              >
                Add to cart
              </button>
              <button
                type="button"
                className={`btn btn-outline ${inWishlist ? 'active' : ''}`}
                onClick={handleWishlist}
              >
                {inWishlist ? '♥ Saved' : '♡ Wishlist'}
              </button>
            </div>
            <div className="product-detail-description">
              <h3>Description</h3>
              <p>{product.description}</p>
            </div>
          </div>
        </div>

        {Array.isArray(product.reviews) && product.reviews.length > 0 && (
          <div className="container product-reviews-block">
            <h2>Customer reviews</h2>
            <ul className="review-list">
              {product.reviews.map((rev) => (
                <li key={rev._id} className="review-item">
                  <strong>{rev.user?.name || 'Customer'}</strong>
                  <StarRatings
                    rating={rev.rating}
                    starRatedColor="var(--gold)"
                    starEmptyColor="#e0ddd6"
                    numberOfStars={5}
                    name={`r-${rev._id}`}
                    starDimension="16px"
                  />
                  <p>{rev.comment}</p>
                </li>
              ))}
            </ul>
          </div>
        )}
      </main>
    </>
  );
}
